const { Given, When, Then } = require('@cucumber/cucumber');
Given('ein registrierter Benutzer', function() { this.user = {email: 'test@test.com'}; });
When('der Benutzer sich anmeldet', function() { this.result = 'dashboard'; });
Then('wird er zum Dashboard weitergeleitet', function() { if(this.result !== 'dashboard') throw new Error('wrong'); });

const { Given, When, Then } = require('@cucumber/cucumber');
let num;
Given('die Zahl {int}', function(n) { num = n; });
When('ich {int} addiere', function(n) { num = num + n; });
When('ich {int} subtrahiere', function(n) { num = num + n; }); // BUG: adds instead of subtracts
Then('ist das Ergebnis {int}', function(expected) { if(num !== expected) throw new Error(`Expected ${expected} but got ${num}`); });

from behave import given, when, then

@given('der Server laeuft')
def step_server_running(context):
    context.base_url = 'http://localhost:8000'

@when('ich GET {path} aufrufe')
def step_get_request(context, path):
    import requests
    context.response = requests.get(f'{context.base_url}{path}')

@then('erhalte ich Status {code:d}')
def step_check_status(context, code):
    assert context.response.status_code == code

const { Given, When, Then } = require('@cucumber/cucumber');
let hour, greeting;
Given('es ist {int} Uhr', function(h) { hour = h; });
When('ich jemanden begruesse', function() { greeting = hour < 12 ? 'Guten Morgen' : 'Guten Abend'; });
Then('sage ich {string}', function(expected) { if(greeting !== expected) throw new Error(`Expected '${expected}' but got '${greeting}'`); });

const { Given, When, Then } = require('@cucumber/cucumber');
let nodes, results;
Given('Knoten mit Labels {string}', function(labels) { nodes = labels.split(', '); });
When('ich nach {string} suche', function(term) { results = nodes.filter(n => n === term); });
Then('wird genau der Knoten {string} gefunden', function(expected) { if(results.length !== 1 || results[0] !== expected) throw new Error('wrong'); });
Then('werden keine Knoten gefunden', function() { if(results.length !== 0) throw new Error('found results'); });
